output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX p: <http://www.wikidata.org/prop/>
SELECT DISTINCT ?ruler ?rulerLabel ?start ?end WHERE {
  ?ruler p:P39 ?statement .
  ?statement ps:P39 wd:Q5107899 .
  OPTIONAL {
    ?statement pq:P580 ?start
  }
  OPTIONAL {
    ?statement pq:P582 ?end
  }
  FILTER(?start <= "1599-12-31" ^^ xsd:date && ?end >= "1500-01-01" ^^ xsd:date)
  OPTIONAL {
    ?ruler rdfs:label ?rulerLabel .
    FILTER(lang(?rulerLabel) = 'en')
  }
}
